+    async function sha256HexFromBuffer(buffer) {
+      const digest = await crypto.subtle.digest("SHA-256", buffer);
+      return Array.from(new Uint8Array(digest)).map((byte) => byte.toString(16).padStart(2, "0")).join("");
+    }
+
+    async function sha256HexFromText(text) {
+      return sha256HexFromBuffer(new TextEncoder().encode(text));
+    }
+
+    async function buildArtifactCatalog() {
+      const catalog = [];
+      const timestamp = new Date().toISOString();
+
+      if (latestFrankenResult?.fmHtml && !latestFrankenResult.fmRenderError && latestFrankenResult.fmHtml.trim().startsWith("<svg")) {
+        const svgText = latestFrankenResult.fmHtml;
+        catalog.push({
+          id: "svg",
+          label: "SVG",
+          mime: "image/svg+xml",
+          bytes: new TextEncoder().encode(svgText).length,
+          hash: await sha256HexFromText(svgText),
+          integrity: "valid svg root",
+          exportValue: svgText,
+          filename: `frankenmermaid-${latestCommittedRevision || 0}.svg`,
+          timestamp
+        });
+      }
+
+      if (els.canvas && typeof els.canvas.toDataURL === "function") {
+        const pngDataUrl = els.canvas.toDataURL("image/png");
+        const pngBase64 = pngDataUrl.split(",")[1] || "";
+        const pngBytes = Uint8Array.from(atob(pngBase64), (char) => char.charCodeAt(0));
+        if (pngBytes.length > 0) {
+          catalog.push({
+            id: "png",
+            label: "PNG",
+            mime: "image/png",
+            bytes: pngBytes.length,
+            hash: await sha256HexFromBuffer(pngBytes.buffer),
+            integrity: "non-empty canvas snapshot",
+            exportValue: pngBytes,
+            filename: `frankenmermaid-${latestCommittedRevision || 0}.png`,
+            timestamp
+          });
+        }
+      }
+
+      if (latestFrankenResult?.parsedValue?.ir) {
+        const irJson = JSON.stringify(latestFrankenResult.parsedValue.ir, null, 2);
+        catalog.push({
+          id: "ir",
+          label: "Parser IR",
+          mime: "application/json",
+          bytes: new TextEncoder().encode(irJson).length,
+          hash: await sha256HexFromText(irJson),
+          integrity: "contains diagram ir payload",
+          exportValue: irJson,
+          filename: `frankenmermaid-ir-${latestCommittedRevision || 0}.json`,
+          timestamp
+        });
+      }
+
+      const statePayload = JSON.stringify({
+        exported_at: timestamp,
+        revision: latestCommittedRevision || 0,
+        state: collectUrlState(),
+        runtime: frankenRuntime?.source || null,
+        studio: studioState,
+        timings: latestFrankenResult?.timings || null,
+        diagnostics: latestFrankenResult?.diagnostics || [],
+        guard: latestFrankenResult?.guardValue || null
+      }, null, 2);
+      catalog.push({
+        id: "state",
+        label: "Config and state",
+        mime: "application/json",
+        bytes: new TextEncoder().encode(statePayload).length,
+        hash: await sha256HexFromText(statePayload),
+        integrity: "contains canonical showcase state",
+        exportValue: statePayload,
+        filename: `frankenmermaid-state-${latestCommittedRevision || 0}.json`,
+        timestamp
+      });
+
+      return catalog;
+    }
+
+    async function renderArtifactLab() {
+      if (!latestFrankenResult) {
+        els.artifactSummary.textContent = "Waiting for a committed render before building export artifacts.";
+        els.artifactBadges.innerHTML = "";
+        els.artifactTable.innerHTML = "";
+        return;
+      }
+
+      const catalog = await buildArtifactCatalog();
+      els.artifactSummary.textContent = `Built ${catalog.length} reproducible artifact record${catalog.length === 1 ? "" : "s"} for revision ${latestCommittedRevision || 0}. Each entry includes size, hash, integrity note, and export format.`;
+      els.artifactBadges.innerHTML = catalog
+        .map((artifact) => `<span class="pill rounded-full px-3 py-1 text-[11px] font-semibold tracking-[0.14em] text-slate-200">${escapeHtml(`${artifact.label} · ${artifact.bytes} bytes`)}</span>`)
+        .join("");
+      const rows = catalog.map((artifact) => `
+        <tr class="border-b border-white/5 align-top">
+          <td class="px-3 py-3 font-medium text-white">${escapeHtml(artifact.label)}</td>
+          <td class="px-3 py-3 text-slate-300">${escapeHtml(artifact.integrity)}</td>
+          <td class="px-3 py-3 text-slate-300">${artifact.bytes}</td>
+          <td class="px-3 py-3 text-slate-300"><code>${escapeHtml(artifact.hash.slice(0, 16))}</code></td>
+          <td class="px-3 py-3 text-slate-500">${escapeHtml(artifact.timestamp)}</td>
+        </tr>
+      `).join("");
+      els.artifactTable.innerHTML = `
+        <table class="min-w-full text-left text-xs">
+          <thead class="sticky top-0 bg-[#08101d] text-slate-400">
+            <tr>
+              <th class="px-3 py-2 font-semibold uppercase tracking-[0.18em]">Artifact</th>
+              <th class="px-3 py-2 font-semibold uppercase tracking-[0.18em]">Integrity</th>
+              <th class="px-3 py-2 font-semibold uppercase tracking-[0.18em]">Bytes</th>
+              <th class="px-3 py-2 font-semibold uppercase tracking-[0.18em]">SHA-256</th>
+              <th class="px-3 py-2 font-semibold uppercase tracking-[0.18em]">Timestamp</th>
+            </tr>
+          </thead>
+          <tbody>${rows}</tbody>
+        </table>
+      `;
+    }
+
+    async function exportArtifact(kind) {
+      const catalog = await buildArtifactCatalog();
+      const artifact = catalog.find((entry) => entry.id === kind);
+      if (!artifact) {
+        els.artifactSummary.textContent = `Artifact ${kind} is not available for the current revision.`;
+        return;
+      }
+      const blob = artifact.id === "png"
+        ? new Blob([artifact.exportValue], { type: artifact.mime })
+        : new Blob([artifact.exportValue], { type: artifact.mime });
+      const url = URL.createObjectURL(blob);
+      const link = document.createElement("a");
+      link.href = url;
+      link.download = artifact.filename;
+      link.click();
+      URL.revokeObjectURL(url);
+      els.artifactSummary.textContent = `Exported ${artifact.label} for revision ${latestCommittedRevision || 0} (${artifact.bytes} bytes, sha256 ${artifact.hash.slice(0, 16)}…).`;
+    }
